/// Tests that codegen produces valid wasm modules.
///
/// Uses wasmparser to validate the generated bytes without executing them.
use std::collections::HashMap;

use majit_backend_wasm::codegen;
use majit_ir::{InputArg, Op, OpCode, OpRef, Type};
use smallvec::smallvec;

fn validate_wasm(bytes: &[u8]) {
    wasmparser::validate(bytes).expect("generated wasm should be valid");
}

fn make_op(opcode: OpCode, args: &[OpRef], pos: OpRef) -> Op {
    let mut op = Op::new(opcode, args);
    op.pos = pos;
    op
}

fn make_guard(opcode: OpCode, args: &[OpRef], fail_args: &[OpRef]) -> Op {
    let mut op = Op::new(opcode, args);
    op.fail_args = Some(smallvec![fail_args[0]; 0]);
    let mut fa: smallvec::SmallVec<[OpRef; 3]> = smallvec::SmallVec::new();
    for &a in fail_args {
        fa.push(a);
    }
    op.fail_args = Some(fa);
    op
}

#[test]
fn test_empty_trace() {
    let inputargs = vec![InputArg {
        index: 0,
        tp: Type::Int,
    }];
    let ops = vec![{
        let mut op = Op::new(OpCode::Finish, &[OpRef(0)]);
        op.fail_args = Some(smallvec![OpRef(0)]);
        op
    }];
    let constants = HashMap::new();
    let (bytes, guards) = codegen::build_wasm_module(
        &inputargs,
        &ops,
        &constants,
        Some(0),
        &HashMap::new(),
        &codegen::GuardGcTypeInfo::default(),
    )
    .expect("wasm codegen should succeed");
    validate_wasm(&bytes);
    assert_eq!(guards.len(), 1);
    assert!(guards[0].is_finish);
}

#[test]
fn test_int_add_loop() {
    // Label(i, sum) -> IntAdd(sum, i) -> IntAdd(i, 1) -> IntLt(i, 100)
    // -> GuardTrue -> Jump(new_i, new_sum)
    let inputargs = vec![
        InputArg {
            index: 0,
            tp: Type::Int,
        }, // i
        InputArg {
            index: 1,
            tp: Type::Int,
        }, // sum
    ];

    let const_1 = OpRef::from_const(0);
    let const_100 = OpRef::from_const(1);
    let mut constants = HashMap::new();
    constants.insert(OpRef::from_const(0).0, 1i64);
    constants.insert(OpRef::from_const(1).0, 100i64);

    let ops = vec![
        Op::new(OpCode::Label, &[OpRef(0), OpRef(1)]),
        make_op(OpCode::IntAdd, &[OpRef(1), OpRef(0)], OpRef(2)), // sum + i
        make_op(OpCode::IntAdd, &[OpRef(0), const_1], OpRef(3)),  // i + 1
        make_op(OpCode::IntLt, &[OpRef(3), const_100], OpRef(4)), // i+1 < 100
        make_guard(OpCode::GuardTrue, &[OpRef(4)], &[OpRef(3), OpRef(2)]),
        Op::new(OpCode::Jump, &[OpRef(3), OpRef(2)]),
    ];

    let (bytes, guards) = codegen::build_wasm_module(
        &inputargs,
        &ops,
        &constants,
        Some(0),
        &HashMap::new(),
        &codegen::GuardGcTypeInfo::default(),
    )
    .expect("wasm codegen should succeed");
    validate_wasm(&bytes);
    assert_eq!(guards.len(), 1); // one guard
    assert!(!guards[0].is_finish);
}

#[test]
fn test_float_ops() {
    let inputargs = vec![
        InputArg {
            index: 0,
            tp: Type::Float,
        },
        InputArg {
            index: 1,
            tp: Type::Float,
        },
    ];

    let ops = vec![
        make_op(OpCode::FloatAdd, &[OpRef(0), OpRef(1)], OpRef(2)),
        make_op(OpCode::FloatSub, &[OpRef(0), OpRef(1)], OpRef(3)),
        make_op(OpCode::FloatMul, &[OpRef(2), OpRef(3)], OpRef(4)),
        make_op(OpCode::FloatTrueDiv, &[OpRef(4), OpRef(0)], OpRef(5)),
        make_op(OpCode::FloatNeg, &[OpRef(5)], OpRef(6)),
        make_op(OpCode::FloatAbs, &[OpRef(6)], OpRef(7)),
        make_op(OpCode::FloatLt, &[OpRef(0), OpRef(1)], OpRef(8)),
        {
            let mut op = Op::new(OpCode::Finish, &[OpRef(7)]);
            op.fail_args = Some(smallvec![OpRef(7)]);
            op
        },
    ];

    let constants = HashMap::new();
    let (bytes, guards) = codegen::build_wasm_module(
        &inputargs,
        &ops,
        &constants,
        Some(0),
        &HashMap::new(),
        &codegen::GuardGcTypeInfo::default(),
    )
    .expect("wasm codegen should succeed");
    validate_wasm(&bytes);
    assert_eq!(guards.len(), 1);
}

#[test]
fn test_call_generates_import() {
    let inputargs = vec![InputArg {
        index: 0,
        tp: Type::Int,
    }];

    let func_ptr = OpRef::from_const(0);
    let mut constants = HashMap::new();
    constants.insert(OpRef::from_const(0).0, 42i64); // fake func_ptr

    let ops = vec![make_op(OpCode::CallI, &[func_ptr, OpRef(0)], OpRef(1)), {
        let mut op = Op::new(OpCode::Finish, &[OpRef(1)]);
        op.fail_args = Some(smallvec![OpRef(1)]);
        op
    }];

    let (bytes, guards) = codegen::build_wasm_module(
        &inputargs,
        &ops,
        &constants,
        Some(0),
        &HashMap::new(),
        &codegen::GuardGcTypeInfo::default(),
    )
    .expect("wasm codegen should succeed");
    validate_wasm(&bytes);
    assert_eq!(guards.len(), 1);

    // Verify the module has jit_call import
    let parser = wasmparser::Parser::new(0);
    let mut has_jit_call = false;
    for payload in parser.parse_all(&bytes) {
        if let Ok(wasmparser::Payload::ImportSection(imports)) = payload {
            for import in imports {
                if let Ok(import) = import {
                    if import.name == "jit_call" {
                        has_jit_call = true;
                    }
                }
            }
        }
    }
    assert!(has_jit_call, "module should import jit_call");
}

#[test]
fn test_guard_types() {
    let inputargs = vec![
        InputArg {
            index: 0,
            tp: Type::Int,
        },
        InputArg {
            index: 1,
            tp: Type::Int,
        },
    ];

    let ops = vec![
        Op::new(OpCode::Label, &[OpRef(0), OpRef(1)]),
        // GuardTrue
        make_guard(OpCode::GuardTrue, &[OpRef(0)], &[OpRef(0), OpRef(1)]),
        // GuardFalse
        make_guard(OpCode::GuardFalse, &[OpRef(1)], &[OpRef(0), OpRef(1)]),
        // GuardValue
        make_guard(OpCode::GuardValue, &[OpRef(0), OpRef(1)], &[OpRef(0)]),
        // GuardNonnull
        make_guard(OpCode::GuardNonnull, &[OpRef(0)], &[OpRef(0)]),
        // GuardIsnull
        make_guard(OpCode::GuardIsnull, &[OpRef(1)], &[OpRef(1)]),
        // GuardNoOverflow (0 args)
        {
            let mut op = Op::new(OpCode::GuardNoOverflow, &[]);
            op.fail_args = Some(smallvec![OpRef(0)]);
            op
        },
        // GuardNotInvalidated (0 args, always pass)
        {
            let mut op = Op::new(OpCode::GuardNotInvalidated, &[]);
            op.fail_args = Some(smallvec![OpRef(0)]);
            op
        },
        Op::new(OpCode::Jump, &[OpRef(0), OpRef(1)]),
    ];

    let constants = HashMap::new();
    let (bytes, guards) = codegen::build_wasm_module(
        &inputargs,
        &ops,
        &constants,
        Some(0),
        &HashMap::new(),
        &codegen::GuardGcTypeInfo::default(),
    )
    .expect("wasm codegen should succeed");
    validate_wasm(&bytes);
    assert_eq!(guards.len(), 7);
}

/// GuardGcType contract in majit: arg0 = object ref, arg1 = expected
/// type_id. The wasm backend reads the GC header word at
/// `obj - GcHeader::SIZE` (matching the cranelift backend and
/// `majit_gc::header::GcHeader` layout) and compares the low
/// `TYPE_ID_BITS` against arg1. arg1 is an immediate type_id, NOT a
/// classptr — no `mem32[obj + 0]` read, no classptr→typeid lookup.
#[test]
fn test_guard_gc_type_uses_immediate_typeid() {
    let inputargs = vec![InputArg {
        index: 0,
        tp: Type::Int,
    }];

    // OpRef::from_const(0) holds the immediate typeid 0x42
    let mut constants = HashMap::new();
    constants.insert(OpRef::from_const(0).0, 0x42_i64);

    let ops = vec![
        Op::new(OpCode::Label, &[OpRef(0)]),
        make_guard(
            OpCode::GuardGcType,
            &[OpRef(0), OpRef::from_const(0)],
            &[OpRef(0)],
        ),
        Op::new(OpCode::Jump, &[OpRef(0)]),
    ];

    let (bytes, guards) = codegen::build_wasm_module(
        &inputargs,
        &ops,
        &constants,
        Some(0),
        &HashMap::new(),
        &codegen::GuardGcTypeInfo::default(),
    )
    .expect("wasm codegen should succeed");
    validate_wasm(&bytes);
    assert_eq!(guards.len(), 1);
}

/// Build a `GuardGcTypeInfo` matching what `WasmBackend::compile_loop`
/// derives from a real `GcLLDescr_framework`-equivalent allocator.
/// Mirrors `gc.py:592 get_translated_info_for_typeinfo` /
/// `gc.py:619 get_translated_info_for_guard_is_object` /
/// `x86/assembler.py:1951 cpu.subclassrange_min_offset`.
fn enabled_guard_gc_type_info() -> codegen::GuardGcTypeInfo {
    let mut info = codegen::GuardGcTypeInfo::default();
    info.supports_guard_gc_type = true;
    // Pretend the TYPE_INFO table sits at a small in-memory address;
    // wasm validation only checks the bytecode shape, not the actual
    // load addresses, so any value works for codegen testing.
    info.base_type_info = 0x1000;
    // majit `TypeEntry` stride = 32 bytes (TypeInfoLayout 16 + ClassTypeLayout 16).
    // shift_by = log2(32) = 5, sizeof_ti = rffi.sizeof(TYPE_INFO) = 16.
    info.shift_by = 5;
    info.sizeof_ti = 16; // size_of::<TypeInfoLayout>()
    // gc.py:603-622 _setup_guard_is_object: T_IS_RPYTHON_INSTANCE
    // = 0x100000 (gctypelayout.py:196), packed little-endian into a
    // Signed word — byte at offset +2 carries the flag, mask = 0x10.
    info.infobits_offset = 2;
    info.is_object_flag = 0x10;
    info.subclassrange_min_offset = 0; // offset within ClassTypeLayout
    info
}

/// x86/assembler.py:1924-1943 `genop_guard_guard_is_object` lowering —
/// the wasm backend's GUARD_IS_OBJECT arm emits the same MOV+addr_add
/// +TEST8+branch sequence. With `supports_guard_gc_type` enabled the
/// `assert` at line 1925 falls through and the rest of the lowering
/// runs; the resulting module must validate as legal wasm.
#[test]
fn test_guard_is_object_lowers_to_typeinfo_test() {
    let inputargs = vec![InputArg {
        index: 0,
        tp: Type::Int,
    }];

    let ops = vec![
        Op::new(OpCode::Label, &[OpRef(0)]),
        make_guard(OpCode::GuardIsObject, &[OpRef(0)], &[OpRef(0)]),
        Op::new(OpCode::Jump, &[OpRef(0)]),
    ];

    let constants = HashMap::new();
    let (bytes, guards) = codegen::build_wasm_module(
        &inputargs,
        &ops,
        &constants,
        Some(0),
        &HashMap::new(),
        &enabled_guard_gc_type_info(),
    )
    .expect("wasm codegen should succeed when supports_guard_gc_type=true");
    validate_wasm(&bytes);
    assert_eq!(guards.len(), 1);
}

/// x86/assembler.py:1945-1980 `genop_guard_guard_subclass` lowering —
/// the wasm backend's GUARD_SUBCLASS arm emits the gcremovetypeptr
/// branch (cpu.vtable_offset = None) when `vtable_offset` is `None`,
/// otherwise the vtable-load branch. With `supports_guard_gc_type`
/// enabled and the constant classptr's `(min, max)` pre-fetched, the
/// lowering runs to completion.
#[test]
fn test_guard_subclass_lowers_to_subclassrange_check() {
    let inputargs = vec![InputArg {
        index: 0,
        tp: Type::Int,
    }];

    let class_constant = OpRef(10_000);
    let mut constants = HashMap::new();
    constants.insert(10_000, 0xCAFEi64);

    let ops = vec![
        Op::new(OpCode::Label, &[OpRef(0)]),
        make_guard(
            OpCode::GuardSubclass,
            &[OpRef(0), class_constant],
            &[OpRef(0)],
        ),
        Op::new(OpCode::Jump, &[OpRef(0)]),
    ];

    let mut info = enabled_guard_gc_type_info();
    // assembler.py:1971-1974: codegen-time
    // (vtable_ptr.subclassrange_min, vtable_ptr.subclassrange_max).
    info.subclass_ranges.insert(0xCAFE, (10, 20));

    // gcremovetypeptr branch: vtable_offset = None.
    let (bytes, guards) =
        codegen::build_wasm_module(&inputargs, &ops, &constants, None, &HashMap::new(), &info)
            .expect("wasm codegen should succeed when supports_guard_gc_type=true");
    validate_wasm(&bytes);
    assert_eq!(guards.len(), 1);

    // vtable-load branch: vtable_offset = Some(...).
    let (bytes2, _) = codegen::build_wasm_module(
        &inputargs,
        &ops,
        &constants,
        Some(8),
        &HashMap::new(),
        &info,
    )
    .expect("wasm codegen should succeed when vtable_offset is set");
    validate_wasm(&bytes2);
}

#[test]
fn test_sameas_and_conversions() {
    let inputargs = vec![InputArg {
        index: 0,
        tp: Type::Int,
    }];

    let ops = vec![
        make_op(OpCode::SameAsI, &[OpRef(0)], OpRef(1)),
        make_op(OpCode::CastIntToFloat, &[OpRef(0)], OpRef(2)),
        make_op(OpCode::CastFloatToInt, &[OpRef(2)], OpRef(3)),
        make_op(OpCode::CastIntToPtr, &[OpRef(0)], OpRef(4)),
        make_op(OpCode::CastPtrToInt, &[OpRef(4)], OpRef(5)),
        make_op(OpCode::IntNeg, &[OpRef(0)], OpRef(6)),
        make_op(OpCode::IntInvert, &[OpRef(0)], OpRef(7)),
        make_op(OpCode::IntIsTrue, &[OpRef(0)], OpRef(8)),
        make_op(OpCode::IntIsZero, &[OpRef(0)], OpRef(9)),
        {
            let mut op = Op::new(OpCode::Finish, &[OpRef(9)]);
            op.fail_args = Some(smallvec![OpRef(9)]);
            op
        },
    ];

    let constants = HashMap::new();
    let (bytes, _) = codegen::build_wasm_module(
        &inputargs,
        &ops,
        &constants,
        Some(0),
        &HashMap::new(),
        &codegen::GuardGcTypeInfo::default(),
    )
    .expect("wasm codegen should succeed");
    validate_wasm(&bytes);
}

#[test]
fn test_overflow_ops() {
    let inputargs = vec![
        InputArg {
            index: 0,
            tp: Type::Int,
        },
        InputArg {
            index: 1,
            tp: Type::Int,
        },
    ];

    let ops = vec![
        make_op(OpCode::IntAddOvf, &[OpRef(0), OpRef(1)], OpRef(2)),
        {
            let mut op = Op::new(OpCode::GuardNoOverflow, &[]);
            op.fail_args = Some(smallvec![OpRef(2)]);
            op
        },
        make_op(OpCode::IntSubOvf, &[OpRef(0), OpRef(1)], OpRef(3)),
        {
            let mut op = Op::new(OpCode::GuardNoOverflow, &[]);
            op.fail_args = Some(smallvec![OpRef(3)]);
            op
        },
        {
            let mut op = Op::new(OpCode::Finish, &[OpRef(2)]);
            op.fail_args = Some(smallvec![OpRef(2)]);
            op
        },
    ];

    let constants = HashMap::new();
    let (bytes, guards) = codegen::build_wasm_module(
        &inputargs,
        &ops,
        &constants,
        Some(0),
        &HashMap::new(),
        &codegen::GuardGcTypeInfo::default(),
    )
    .expect("wasm codegen should succeed");
    validate_wasm(&bytes);
    assert_eq!(guards.len(), 3); // 2 GuardNoOverflow + 1 Finish
}
